+		t.Fatalf("unexpected list size")
+	}
+	defaults, err := ParseList(nil)
+	if err != nil {
+		t.Fatalf("ParseList default: %v", err)
+	}
+	if len(defaults) != 1 || defaults[0] != Spectrogram {
+		t.Fatalf("unexpected default list")
