+func TestRenderUnknown(t *testing.T) {
+	ctx := NewContext(testSamples(), 44100, 512, 128)
+	_, err := Render(Kind("nope"), ctx, RenderOptions{Width: 10, Height: 10, Palette: colorRGBA})
+	if err == nil {
+		t.Fatalf("expected error")
+	}
