+func testSamples() []float64 {
+	samples := make([]float64, 4096)
+	for i := range samples {
+		t := float64(i) / 4096
+		samples[i] = 0.6*math.Sin(2*math.Pi*440*t) + 0.2*math.Sin(2*math.Pi*880*t)
+	}
+	return samples
+}
